UPDATE dp_area_panel
area_id = #{areaId}, panel_id = #{panelId}, panel_sort_ord = #{panelSortOrd}, visibility_targets = #{visibilityTargets}, disp_yn = #{dispYn}, disp_start_date = #{dispStartDate}, disp_start_time = #{dispStartTime}, disp_end_date = #{dispEndDate}, disp_end_time = #{dispEndTime}, disp_env = #{dispEnv}, use_yn = #{useYn}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE area_panel_id = #{areaPanelId}
